class Solution:
    def solve(self, nums, queries):
        import sys
        sys.setrecursionlimit(1 << 25)
        n = len(nums)
        maxK = 5
        class FenwickTree:
            def __init__(self, size):
                self.size = size
                self.tree = [0] * (size + 2)

            def update(self, index, delta):
                index += 1  # 1-based
                while index <= self.size:
                    self.tree[index] += delta
                    index += index & -index

            def query(self, index):
                index += 1  # 1-based
                res = 0
                while index > 0:
                    res += self.tree[index]
                    index -= index & -index
                return res

            def rangeQuery(self, l, r):
                return self.query(r) - self.query(l - 1)

        ft = [FenwickTree(n) for _ in range(maxK + 1)]

        def computeDepth(x):
            depth = 0
            while x != 1:
                x = bin(x).count('1')
                depth += 1
            return depth

        depths = [0] * n
        for i in range(n):
            depths[i] = computeDepth(nums[i])

        for i in range(n):
            d = depths[i]
            if d <= maxK:
                ft[d].update(i, 1)

        answer = []
        for q in queries:
            if q[0] == 1:
                l = q[1]
                r = q[2]
                k = q[3]
                if k > maxK:
                    answer.append(0)
                    continue
                res = ft[k].rangeQuery(l, r)
                answer.append(res)
            else:
                idxQ = q[1]
                val = q[2]
                oldD = depths[idxQ]
                if oldD <= maxK:
                    ft[oldD].update(idxQ, -1)
                nums[idxQ] = val
                newD = computeDepth(val)
                if newD <= maxK:
                    ft[newD].update(idxQ, 1)
                depths[idxQ] = newD

        return answer
