public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = getDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[6];
        for (int k = 0; k < 6; k++) {
            ft[k] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
            int d = depths[i];
            ft[d].update(i + 1, 1);
        }

        long[] answer = new long[queries.length];
        int idx = 0;

        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                answer[idx++] = ft[k].rangeQuery(l + 1, r + 1);
            } else {
                int idxNum = (int) q[1];
                long newVal = q[2];
                int oldDepth = depths[idxNum];
                ft[oldDepth].update(idxNum + 1, -1);
                nums[idxNum] = newVal;
                int newDepth = getDepth(newVal);
                ft[newDepth].update(idxNum + 1, 1);
                depths[idxNum] = newDepth;
            }
        }

        return answer;
    }

    private static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new int[size + 1];
        }

        public void update(int index, int delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int query(int index) {
            int res = 0;
            while (index > 0) {
                res += tree[index];
                index -= index & -index;
            }
            return res;
        }

        public int rangeQuery(int l, int r) {
            return query(r) - query(l - 1);
        }
    }

    private static int getDepth(long x) {
        if (x == 1) return 0;
        int count = Long.bitCount(x);
        return 1 + getDepth(count);
    }
}
