public class Solution {
    static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new int[size + 1]; // 1-based indexing
        }

        public void update(int index, int delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int rangeSum(int l, int r) {
            return query(r) - query(l - 1);
        }

        private int query(int index) {
            int res = 0;
            while (index > 0) {
                res += tree[index];
                index -= index & -index;
            }
            return res;
        }
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[6];
        for (int i = 0; i < 6; i++) {
            ft[i] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
