public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[6];
        for (int i = 0; i < 6; i++) {
            ft[i] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
            int d = depths[i];
            ft[d].update(i + 1, 1);
        }

        long[] answer = new long[queries.length];
        int qIdx = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                answer[qIdx++] = ft[k].rangeSum(l + 1, r + 1);
            } else {
                int idx = (int) query[1];
                long val = query[2];
                long oldVal = nums[idx];
                int oldD = depths[idx];
                ft[oldD].update(idx + 1, -1);
                nums[idx] = val;
                int newD = computeDepth(val);
                depths[idx] = newD;
                ft[newD].update(idx + 1, 1);
            }
        }

        return answer;
    }

    static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new int[size + 1];
        }

        public void update(int index, int delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int rangeSum(int l, int r) {
            return rangeSum(r) - rangeSum(l - 1);
        }

        private int rangeSum(int index) {
            int sum = 0;
            while (index > 0) {
                sum += tree[index];
                index -= index & -index;
            }
            return sum;
        }
    }

    private static int computeDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}
